{
  "name": "MaineCare Elderly and Adults with Disabilities Waiver",
  "eligibility": {
    "age": "65+ or 18+ with physical disabilities",
    "income_limits": "Determined by Office of Family Independence (OFI) under MaineCare financial eligibility rules; specific dollar amounts or household size tables not detailed in sources—use MaineCare Eligibility Test for seniors via American Council on Aging[1]",
    "asset_limits": "Not specified in sources; follows standard MaineCare long-term care rules—consult OFI for details[1]",
    "other_requirements": [
      "Maine resident",
      "Nursing Facility Level of Care (NFLOC) determined by in-person functional needs assessment using Medical Eligibility Determination (MED) tool by a registered nurse[1]",
      "At risk of institutionalization (nursing home admission)[1]"
    ]
  },
  "benefits": {
    "type": "service",
    "value": "Care coordination, personal care, respite, financial management services, skills training, assistive technology, attendant care services, environmental modifications, home delivered meals, home health services, living well for better health (chronic disease self-management), matter of balance (falls prevention), non-medical transportation, personal emergency response system, non-traditional communication consultation/assessments, occupational/physical/speech therapy (maintenance), shared living (adult foster care), specialized medical equipment and supplies[2]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": [
      "Online: My Maine Connection[1]",
      "Phone: Office for Family Independence at 855-797-4357[1]",
      "In-person: District Department of Health and Human Services office[1]",
      "Mail: Download and print Application for Long Term Care MaineCare[1]"
    ],
    "processing_time": "Up to 90 days for determination[5]",
    "waitlist": "Exists; average wait time varies by needs and can range from no time to several years[5]",
    "forms": [
      "Application for Long Term Care MaineCare[1]"
    ],
    "documents": [
      "Documents for financial and medical eligibility (specifics determined by OFI and Assessing Services Agency; may require additional after initial application)[5]"
    ]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None",
    "regional_variations": "Administered statewide by DHHS Office of Aging and Disability Services (OADS); functional eligibility by Assessing Services Agency; possible regional wait time differences not detailed[1][4]",
    "offices_or_providers": [
      "District DHHS offices for in-person[1]"
    ]
  },
  "official_source": "https://www.maine.gov/dhhs/oms/mainecare-options/older-adults-and-adults-with-disabilities[4]",
  "gotchas": [
    "Must meet both financial (OFI) and functional (Assessing Services Agency) eligibility separately[1]",
    "Requires Nursing Facility Level of Care (NFLOC)—not just disability[1]",
    "Waitlists can be several years depending on needs[5]",
    "Estate recovery possible if received services age 55+ and no surviving spouse or qualifying children[4]",
    "Only one waiver at a time; distinguish from other waivers like those for intellectual disabilities[2][5]"
  ],
  "data_shape_notes": "Statewide with waitlist; benefits detailed by service type with tiered/priority access; dual eligibility determination (financial + functional); monthly/annual service caps updated periodically[1][2][3]"
}

{
  "name": "State Health Insurance Assistance Program (SHIP) - Maine Senior Health Insurance Assistance Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits or asset limits. Open to all Maine residents with Medicare or expecting Medicare, including those 65+ and people with Medicare due to disability.",
    "asset_limits": "No asset limits or test.",
    "other_requirements": ["Must be a Maine resident", "Must have Medicare or expect to have Medicare soon (includes older adults and those with Medicare due to disability)"]
  },
  "benefits": {
    "type": "service",
    "value": "Free, confidential counseling services including: information on Medicare, Medicare Advantage, MaineCare, Medigap, and supplemental programs; preventive health benefits; Medicare Part D options; help with medical bills, claims, and notices. Counselors do not sell insurance or recommend policies.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 1-800-262-2232", "Website: https://www.maine.gov/dhhs/oads/get-support/older-adults-disabilities/older-adult-services/ship-medicare-assistance", "In-person or local: Contact via phone for local counselors through Maine's five Area Agencies on Aging"],
    "processing_time": "No formal application or processing time; services available immediately upon contact.",
    "waitlist": null,
    "forms": ["No specific forms required"],
    "documents": ["No documents needed to start; may request Medicare info or bills for specific help"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available throughout Maine",
    "regional_variations": "Services delivered through five regional Area Agencies on Aging and local counselors, but core services uniform statewide; no noted differences in wait times or offerings.",
    "offices_or_providers": ["Sponsored by Office of Aging and Disability Services, Maine's five Area Agencies on Aging, and Legal Services for Maine Elders, Inc.", "Main office: Office of Aging and Disability Services, 11 State House Station, 41 Anthony Ave., Augusta, ME 04333"]
  },
  "official_source": "https://www.maine.gov/dhhs/oads/get-support/older-adults-disabilities/older-adult-services/ship-medicare-assistance",
  "gotchas": ["Not an insurance or financial aid program—provides counseling only, no direct payments or coverage.", "Counselors do not sell or recommend specific policies.", "Not limited to seniors; includes younger people with Medicare due to disability.", "Separate from MaineCare/Medicaid eligibility which has income/asset rules.", "No online application form; contact by phone or website to connect with counselor."],
  "data_shape_notes": "no income test; open to all Medicare beneficiaries; service-based counseling only; delivered via regional Area Agencies on Aging but uniform benefits statewide"
}

{
  "name": "Maine Legal Services for the Elderly",
  "eligibility": {
    "age": 60,
    "income_limits": "Specific dollar amounts or tables not detailed in sources; services targeted to 'socially and economically needy' elderly, often at or below 200% of federal poverty guidelines based on similar programs, but exact limits determined case-by-case for priority[2][4][7].",
    "asset_limits": "No asset limits specified in sources.",
    "other_requirements": ["Maine resident", "Basic human needs at stake (e.g., MaineCare/Medicare issues, elder abuse, housing, public benefits)", "Priority for those with income-related barriers; referrals if ineligible[2][4][9]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free legal services including information, advice, and representation on: Medicare/MaineCare disputes, health coverage, elder abuse/protection orders, housing (eviction/foreclosure), consumer debt, public assistance benefits, guardianship, discharges from care, powers of attorney, health care advance directives, Medicare Part D prescription drug assistance[2][4][9].",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Phone: Helpline 1-800-750-5353 (in-state) or 207-623-1797[2][4][6][9]", "Website: https://mainelse.org for information and Elder Rights Handbook[2][9]", "In-person: Attorneys in offices across the state for representation cases[4]"],
    "processing_time": "Not specified.",
    "waitlist": null,
    "forms": ["No specific application form required; contact helpline for intake[2]"],
    "documents": ["Not explicitly listed; prepare proof of age, residency, income details, and documents related to legal issue (e.g., MaineCare notices, eviction papers)[2]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available to Maine residents age 60+[2][4][6][9]",
    "regional_variations": "Attorneys located in offices across the state; funded through Bureau of Elder and Adult Services and Area Agencies on Aging (AAA), potential minor differences in local providers[4][5].",
    "offices_or_providers": ["Offices across Maine; coordinated with AAAs[4][5]"]
  },
  "official_source": "https://mainelse.org[9]",
  "gotchas": ["Not a general entitlement; services prioritized for those with basic needs at stake and economic need—may get advice/referral only[2][4]", "Avoid pre-printed powers of attorney forms from stores/internet as some are invalid in Maine; consult LSE attorney[2]", "If ineligible, referred to private attorneys possibly at reduced fees[4]", "Focuses on non-criminal civil legal issues, not broad healthcare/financial aid[4]"],
  "data_shape_notes": "No fixed income/asset tables; eligibility prioritizes 'socially and economically needy' with case-by-case review; statewide helpline with regional attorney offices; services are legal advocacy, not direct financial or in-kind aid"
}

{
  "name": "Legal Services for Maine Elders (LSE)",
  "eligibility": {
    "age": 60,
    "income_limits": "No specific dollar amounts or tables provided in sources; eligibility based on being 'socially and/or economically needy' for persons age 60 and over. Other legal aid programs reference up to 200% of federal poverty guidelines, but not explicitly confirmed for LSE[2][4].",
    "asset_limits": "No asset limits or details on what counts/exempts mentioned in sources.",
    "other_requirements": ["Maine resident", "Age 60 and over", "Basic human needs at stake (e.g., health care, housing, abuse)", "Non-criminal legal problems"]
  },
  "benefits": {
    "type": "service",
    "value": "Free legal advice, information, and in some cases representation on: health care, health insurance, Medicare (including Part D), MaineCare (Medicaid), Social Security/public benefits, pension/retirement benefits, powers of attorney, consumer matters (creditor/debt/bankruptcy), physical/financial abuse, guardianship defense, housing (eviction/foreclosure), elder abuse/protection orders, discharges, health care advance directives. Medicare Part D Unit for prescription drug issues[2][3][7].",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Helpline 1-800-750-5353 (in-state) or 207-623-1797; Medicare Part D Unit: 1-877-774-7772", "Website: www.mainelse.org", "In-person: Attorneys in offices across the state for representation cases"],
    "processing_time": "Not specified in sources.",
    "waitlist": "Limited resources mean not all demands can be met; referrals to private attorneys if unable to help[3][4].",
    "forms": [],
    "documents": "Not specified; prepare details on legal issue for helpline consultation."
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available to Maine residents age 60+.",
    "regional_variations": "Attorneys located in offices across the state; no specific differences in services, wait times, or providers by region noted[3].",
    "offices_or_providers": ["Offices across the state (specific locations not listed)"]
  },
  "official_source": "https://www.maine.gov/dhhs/oads/get-support/older-adults-disabilities/older-adult-services/legal-assistance and https://mainelse.org[2][7]",
  "gotchas": ["Limited resources; may not take all cases and provide referrals instead[3][4]", "Helpline hours: 9am-12pm and 1pm-4pm[3]", "Focus on non-criminal matters; separate Medicare Part D unit with different phone[2][3]", "Partnership with Area Agencies on Aging, but contact LSE directly[2]"],
  "data_shape_notes": "No fixed income/asset tables or strict financial tests detailed; eligibility emphasizes 'socially/economically needy' age 60+ Maine residents; statewide with offices but resource-limited; helpline primary access with potential representation."
}
